<?php
/** _ssdi_rmhub.php — remove the state-hub from deeppink. Key-guarded, self-deletes. */
error_reporting(E_ALL); ini_set('display_errors','1');
if (($_GET['key'] ?? '') !== 'rmhub-8w2') { http_response_code(403); exit('forbidden'); }
header('Content-Type: text/plain; charset=utf-8');
$APPROOT = '/home/u128533805/domains/deeppink-partridge-979149.hostingersite.com';
$log = [];
$FILES = [
  'public_html/index.php' => '',
  'includes/repo.php' => '',
  'templates/condition.php' => '',
  'templates/sitemap.php' => '',
];
foreach ($FILES as $rel => $b64) {
    $dst = $APPROOT.'/'.$rel; $data = base64_decode($b64, true);
    $tmp = $dst.'.tmp'.getmypid();
    if ($data!==false && file_put_contents($tmp,$data)!==false && @rename($tmp,$dst)) $log[]="wrote $rel (".strlen($data)." b)";
    else { @unlink($tmp); $log[]="WRITE FAIL: $rel"; }
}
foreach (['templates/states-hub.php','templates/state.php','templates/city.php'] as $rel) {
    $f = $APPROOT.'/'.$rel;
    if (is_file($f)) { $log[] = @unlink($f) ? "deleted $rel" : "DELETE FAIL: $rel"; }
    else $log[] = "absent $rel";
}
$cdir = $APPROOT.'/storage/cache'; $n=0;
if (is_dir($cdir)) { $it = new RecursiveIteratorIterator(new RecursiveDirectoryIterator($cdir, FilesystemIterator::SKIP_DOTS), RecursiveIteratorIterator::CHILD_FIRST);
  foreach ($it as $f) { if ($f->isFile()) { @unlink($f->getPathname()); $n++; } } }
$log[] = "cache cleared ($n files)";
echo "=== RM-HUB REPORT ===\n".implode("\n",$log)."\n=== DONE ===\n";
@unlink(__FILE__); echo "(removed itself)\n";
